import React, { useEffect } from 'react';
import AOS from 'aos';
import styled from 'styled-components';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { 
  faBullseye, 
  faEye, 
  faLightbulb, 
  faUsers, 
  faTrophy, 
  faSeedling, 
  faGlobeAmericas, 
  faRocket 
} from '@fortawesome/free-solid-svg-icons';

const Section = styled.section`
  padding: 100px 10%;
  position: relative;
  overflow: hidden;
`;

const Container = styled.div`
  max-width: 1200px;
  margin: auto;
  position: relative;
  z-index: 2;
`;

const Header = styled.div`
  text-align: center;
  margin-bottom: 60px;

  h2 {
    font-size: 3rem;
    color: #00FFFF;
    margin-bottom: 20px;
    position: relative;
    display: inline-block;

    &::after {
      content: '';
      position: absolute;
      bottom: -10px;
      left: 50%;
      transform: translateX(-50%);
      width: 80px;
      height: 4px;
      background: linear-gradient(to right, #00FFFF, #00BFFF);
      border-radius: 2px;
    }
  }
`;

const Content = styled.div`
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 40px;
  margin-bottom: 60px;

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
`;

const Card = styled.div`
  background: rgba(255, 255, 255, 0.05);
  border-radius: 20px;
  padding: 30px;
  border: 1px solid rgba(255, 255, 255, 0.1);

  h3 {
    font-size: 1.8rem;
    color: #00FFFF;
    margin-bottom: 20px;
    display: flex;
    align-items: center;
    gap: 15px;
  }

  p {
    color: rgba(255, 255, 255, 0.9);
    line-height: 1.8;
  }
`;

const Values = styled.div`
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 30px;

  @media (max-width: 768px) {
    grid-template-columns: repeat(2, 1fr);
  }

  @media (max-width: 480px) {
    grid-template-columns: 1fr;
  }
`;

const ValueItem = styled.div`
  text-align: center;
  padding: 30px 20px;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 15px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: transform 0.3s ease;

  &:hover {
    transform: translateY(-10px);
  }

  i {
    font-size: 2rem;
    color: #00FFFF;
    margin-bottom: 20px;
  }

  h4 {
    color: #00FFFF;
    margin: 15px 0;
    font-size: 1.2rem;
  }

  p {
    color: rgba(255, 255, 255, 0.8);
  }
`;

const Mission = () => {
  useEffect(() => {
    AOS.init({
      duration: 800,
      once: true
    });
  }, []);

  const values = [
    { icon: faLightbulb, title: 'Innovation', description: 'Pushing boundaries and creating new solutions' },
    { icon: faUsers, title: 'Teamwork', description: 'Collaborating to achieve common goals' },
    { icon: faTrophy, title: 'Excellence', description: 'Striving for the highest standards' },
    { icon: faSeedling, title: 'Growth Mindset', description: 'Continuous learning and development' },
    { icon: faGlobeAmericas, title: 'Community Impact', description: 'Making a positive difference together' },
    { icon: faRocket, title: 'Leadership', description: 'Inspiring and guiding others to success' }
  ];

  return (
    <Section id="mission">
      <Container>
        <Header>
          <h2 data-aos="fade-up">Our Mission & Vision</h2>
        </Header>

        <Content>
          <Card data-aos="fade-right">
            <h3>
              <FontAwesomeIcon icon={faBullseye} />
              Our Mission
            </h3>
            <p>
              At <strong>Optimus</strong>, we're dedicated to creating a dynamic space where innovation thrives. Our
              mission is to empower students through hands-on learning, collaborative projects, and real-world challenges.
              We believe in nurturing talent and providing the tools needed to turn ideas into impactful solutions.
            </p>
          </Card>

          <Card data-aos="fade-left">
            <h3>
              <FontAwesomeIcon icon={faEye} />
              Our Vision
            </h3>
            <p>
              We envision a future where every student has the opportunity to develop their technical skills and
              leadership abilities. Our goal is to build a community that not only learns together but also creates
              lasting impact through technology and innovation.
            </p>
          </Card>
        </Content>

        <Header style={{ marginTop: '60px' }}>
          <h2 data-aos="fade-up">Core Values</h2>
        </Header>

        <Values>
          {values.map((value, index) => (
            <ValueItem
              key={index}
              data-aos="zoom-in"
              data-aos-delay={100 * (index + 1)}
            >
              <FontAwesomeIcon icon={value.icon} size="2x" color="#00FFFF" />
              <h4>{value.title}</h4>
              <p>{value.description}</p>
            </ValueItem>
          ))}
        </Values>
      </Container>
    </Section>
  );
};

export default Mission;
